import axios from 'axios';

// API基础URL
const API_BASE_URL = 'http://localhost:8080/api';

// 创建axios实例
const apiClient = axios.create({
  baseURL: API_BASE_URL,
  timeout: 60000, // 60秒超时
  headers: {
    'Content-Type': 'multipart/form-data',
  }
});

/**
 * 上传小说文件
 * @param {File} file - 小说文件
 * @param {string} title - 小说标题
 * @param {string} author - 作者名
 * @returns {Promise} - API响应
 */
export const uploadNovelFile = async (file, title, author) => {
  const formData = new FormData();
  formData.append('file', file);
  formData.append('title', title);
  if (author) {
    formData.append('author', author);
  }

  try {
    const response = await apiClient.post('/novels/upload/txt', formData);
    return response.data;
  } catch (error) {
    console.error('上传小说文件失败:', error);
    throw error;
  }
};

/**
 * 从URL获取小说
 * @param {string} url - 小说URL
 * @param {string} title - 小说标题
 * @param {string} author - 作者名
 * @returns {Promise} - API响应
 */
export const fetchNovelFromUrl = async (url, title, author) => {
  const formData = new FormData();
  formData.append('url', url);
  formData.append('title', title);
  if (author) {
    formData.append('author', author);
  }

  try {
    const response = await apiClient.post('/novels/fetch/url', formData);
    return response.data;
  } catch (error) {
    console.error('获取小说URL失败:', error);
    throw error;
  }
};

/**
 * 获取小说处理结果
 * @param {number} novelId - 小说ID
 * @returns {Promise} - API响应
 */
export const getNovelDetails = async (novelId) => {
  try {
    const response = await apiClient.get(`/novels/${novelId}`);
    return response.data;
  } catch (error) {
    console.error('获取小说详情失败:', error);
    throw error;
  }
};

/**
 * 获取小说处理状态
 * @param {number} novelId - 小说ID
 * @returns {Promise} - API响应
 */
export const getNovelStatus = async (novelId) => {
  try {
    const response = await apiClient.get(`/novels/${novelId}/status`);
    return response.data;
  } catch (error) {
    console.error('获取小说状态失败:', error);
    throw error;
  }
};

/**
 * 获取小说列表
 * @returns {Promise} - API响应
 */
export const getNovelsList = async () => {
  try {
    const response = await apiClient.get('/novels');
    return response.data;
  } catch (error) {
    console.error('获取小说列表失败:', error);
    throw error;
  }
};

// 导出API服务
export default {
  uploadNovelFile,
  fetchNovelFromUrl,
  getNovelDetails,
  getNovelStatus,
  getNovelsList
};
